import Chart from 'chart.js/auto';
import { getDataFromAPI } from "../server/server";

(async function () {
    const apiData = await getDataFromAPI('/v2/pia').then(data => {
        return data;
    });

    const chartData = apiData?.ac.slice(0, 10).map(data => {
        return { lat: data.lat.toString().substring(0, data.lat.toString().indexOf('.')), long: data.lon.toString().substring(0, data.lon.toString().indexOf('.')), planeInfo: data.plane }; // Include plane information in the chart data
    });

    const scatterChart = new Chart(
        document.getElementById('scatterChart'),
        {
            type: 'scatter',
            data: {
                datasets: [{
                    label: 'Plane locations on scatter chart',
                    data: chartData.map(row => ({ x: row.lat, y: row.long, plane: row.planeInfo }))
                }]
            },
            options: {
                onClick: (event, elements) => {
                    if (elements.length > 0) {
                        const clickedPoint = elements[0];
                        const planeInfo = clickedPoint.dataset.data[clickedPoint.dataIndex].plane;
                        alert(`Plane Info: ${planeInfo}`);
                        // You can also update the DOM to display the plane info instead of using alert()
                    }
                },
                // Add other options as needed
            }
        }
    );
})();